def _parse_llm_response(self, response) -> LLMResponse:
    """将 OpenAI API 原始响应解析为 LLMResponse 数据类"""
    if not response.choices:
        # API 返回了空的 choices（可能是上下文过长、内容过滤等原因）
        return LLMResponse(
            content="[API 返回了空响应，可能是上下文过长或触发了内容过滤]",
            tool_calls=[],
            finish_reason="error",
            usage={},
        )
    choice = response.choices[0]
    message = choice.message

    # 解析工具调用
    tool_calls = []
    if message.tool_calls:
        for tc in message.tool_calls:
            try:
                arguments = json.loads(tc.function.arguments)
            except (json.JSONDecodeError, TypeError):
                arguments = {}
            tool_calls.append(ToolCallRequest(
                id=tc.id,
                name=tc.function.name,
                arguments=arguments,
            ))

    # 解析 usage
    usage_dict = {}
    if response.usage:
        usage_dict = {
            "prompt_tokens": response.usage.prompt_tokens,
            "completion_tokens": response.usage.completion_tokens,
            "total_tokens": response.usage.total_tokens,
        }

    # 解析 reasoning_content（DeepSeek-R1 / Kimi 等）
    reasoning_content = getattr(message, 'reasoning_content', None)

    # 解析 thinking_blocks（Anthropic）
    thinking_blocks = getattr(message, 'thinking_blocks', None)

    return LLMResponse(
        content=message.content,
        tool_calls=tool_calls,
        finish_reason=choice.finish_reason or "stop",
        usage=usage_dict,
        reasoning_content=reasoning_content,
        thinking_blocks=thinking_blocks,
    )

